INSERT INTO `education` (`id`, `course_name`, `organization_name`, `duration`, `grade`, `percentage`, `description`, `status`, `created_at`, `updated_at`) VALUES
(1, 'Secondary Education Examination (S.E.E)', 'Mahendra Rastriya Ma. Vi School, Ramgopalpur , Mahottari, Nepal', '2017 Passout', '2.4 / 4', '60', 'My school days at Mahendra Rastriya Ma. Vi School in Ramgopalpur, Nepal, specifically in Class 10, were memorable. The academic atmosphere, inspiring teachers, and camaraderie among classmates left a lasting impact. These formative years laid the groundwork for my educational and personal growth.', 1, '2024-02-05 17:21:10', '2024-02-21 21:01:31'),
(3, 'Diploma in Computer Science and Engineering', 'jagannath university, jaipur', '2017 - 2020', '6.53 / 10', '64', 'While pursuing my Diploma in Computer Science and Engineering at Jagannath University, Jaipur, from 2017 to 2020, I flourished in an environment that fostered growth. The committed faculty, coupled with an outstanding education system, sculpted my academic path. Reflecting on cherished memories, I am grateful for the transformative experience that has profoundly influenced my career foundation.', 1, '2024-02-15 18:16:10', '2024-02-21 21:09:01'),
(4, 'B.SC. Information Technology', 'Rabindranath Tagore University, bhopal, MP', '2020-2023', '8.5 / 10', '85', 'During my B.Sc. Information Technology at Rabindranath Tagore University, Bhopal, MP (2020-2023), I thrived in a supportive educational environment. Engaging with dedicated teachers and experiencing a robust education system, I fondly recall the nurturing atmosphere that fostered lasting memories distinct from my previous diploma program.', 1, '2024-02-21 21:07:32', '2024-02-21 21:07:32');

