INSERT INTO `experiences` (`id`, `designation`, `company_name`, `location`, `duration`, `description`, `status`, `created_at`, `updated_at`) VALUES
(2, 'php developer (intern)', 'Gempulse Infotech Pvt ltd', 'Jaipur, Rajasthan', '01 jan 2020 - 25 feb 2020', 'As a PHP intern at Gempulse Infotech Pvt Ltd in Jaipur, Rajasthan, I contributed from January 1, 2020, to February 25, 2020. During my tenure, I successfully developed numerous projects, showcasing my skills and commitment to delivering quality results in the dynamic field of web development.', 1, '2024-02-15 18:43:09', '2024-02-21 20:49:19'),
(3, 'Php laravel developer', 'Script Qube Pvt. Ltd.', 'Janakpur, Nepal', '01 June 2022 - 30 Jun 2023', 'As a PHP Laravel Developer at Script Qube Pvt. Ltd. (Janakpur, Nepal) from June 2022 to June 2023, I developed and maintained several web applications, focusing on both backend and frontend development. I utilized PHP, Laravel, and MySQL to build robust, scalable server-side applications, while incorporating HTML, CSS, JavaScript, AJAX, and Bootstrap to create responsive, user-friendly interfaces. I worked collaboratively with cross-functional teams to deliver high-quality projects on time, ensuring performance, security, and maintainability. My role involved the complete software development lifecycle, from design to deployment.', 1, '2024-02-18 16:51:43', '2025-03-04 08:00:45'),
(4, 'Full-Stack Developer', 'AmazingWeb.Design', 'Bhopal, MP', '3 july 2023 - present', 'I am currently a Full-Stack Developer at AmazingWeb.Design, where I have been contributing since July 3, 2023. In my role, I specialize in developing mobile applications, as well as frontend and backend web solutions. My expertise spans a wide array of technologies, including HTML, CSS, JavaScript, AJAX, jQuery, Bootstrap, MySQL, PHP, Laravel, React.js, React Native, MongoDB, Node.js, and Express.js.\r\n\r\nI am actively involved in designing and developing multiple projects using these technologies, delivering high-quality, scalable solutions across web and mobile platforms. My work focuses on creating seamless user experiences while ensuring robust performance and efficient back-end architectures.', 1, '2024-12-09 18:35:29', '2025-03-04 07:58:58');

