INSERT INTO `features` (`id`, `icon`, `title`, `description`, `status`, `created_at`, `updated_at`) VALUES
(2, 'fa fa-code', 'web development', 'I have extensive experience in both frontend and backend website development.\r\n\r\nOn the frontend, I utilize HTML, CSS, JavaScript, TypeScript, React.js, Next.js, Tailwind CSS, and Bootstrap to create dynamic, responsive user interfaces that enhance user engagement.\r\nFor backend development, I work with PHP, Laravel, Node.js, MySQL, and MongoDB to build robust, scalable systems that ensure high performance and security.\r\nMy focus is on delivering high-performance, secure, and user-centric web solutions that meet business and user needs efficiently', '1', '2024-01-25 16:19:05', '2025-03-04 07:55:48'),
(5, 'fa-solid fa-mobile', 'App Development', 'I have developed mobile applications for both Android and iOS platforms, leveraging React Native and other modern frameworks to build seamless, high-performing applications. My focus is on creating intuitive, user-friendly experiences, optimizing performance, and ensuring smooth cross-platform compatibility. I am committed to enhancing app functionality, improving UI/UX, and delivering high-quality, responsive solutions that meet both user and business needs', '1', '2024-12-09 19:57:15', '2025-03-04 07:56:56');

