(2, 'Auction Deal Assist (1st Project)', 'Development', 'https://www.auctiondealassist.com/', 'portfolio/09-05-2024-22-28-081715273888.png', '[\"portfolio\\/2024-05-09-23-00-17017152758170.png\",\"portfolio\\/2024-05-09-23-00-17117152758171.png\",\"portfolio\\/2024-05-09-23-00-17217152758172.png\",\"portfolio\\/2024-05-09-23-00-17317152758173.png\",\"portfolio\\/2024-05-09-23-00-17417152758174.png\",\"portfolio\\/2024-05-09-23-00-17517152758175.png\",\"portfolio\\/2024-05-09-23-00-17617152758176.png\",\"portfolio\\/2024-05-09-23-00-17717152758177.png\",\"portfolio\\/2024-05-09-23-00-17817152758178.png\",\"portfolio\\/2024-05-09-23-00-17917152758179.png\",\"portfolio\\/2024-05-09-23-00-1710171527581710.png\",\"portfolio\\/2024-05-09-23-00-1711171527581711.png\",\"portfolio\\/2024-05-09-23-00-1712171527581712.png\",\"portfolio\\/2024-05-09-23-00-1713171527581713.png\",\"portfolio\\/2024-05-09-23-00-1714171527581714.png\",\"portfolio\\/2024-05-09-23-00-1715171527581715.png\",\"portfolio\\/2024-05-09-23-00-1716171527581716.png\",\"portfolio\\/2024-05-09-23-00-1717171527581717.png\",\"portfolio\\/2024-05-09-23-00-1718171527581718.png\",\"portfolio\\/2024-05-09-23-00-1719171527581719.png\"]', '<p><strong>#Auction Deal Assist (Property Dealer Project)</strong></p>\r\n\r\n<p><strong>Introduction:</strong> The Auction Deal Assist Property Dealer Project is a Laravel-based web application designed to provide a platform for property dealers to list and manage properties across various states. This report outlines the key features of both the frontend and backend components of the project.</p>\r\n\r\n<p><strong>Frontend Features:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Menus:</strong></p>\r\n\r\n	<ul>\r\n		<li>Home: Provides an overview of the platform and its services.</li>\r\n		<li>Listings: Displays available properties for users to browse.</li>\r\n		<li>Subscriptions: Allows users to view subscription plans and sign up for them.</li>\r\n		<li>About Us: Provides information about the company or organization behind the platform.</li>\r\n		<li>Contact Us: Enables users to reach out for inquiries or support.</li>\r\n		<li>Join Us: Facilitates the registration process for new users.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>User Authentication:</strong></p>\r\n\r\n	<ul>\r\n		<li>Registration: Allows users to create an account with the platform.</li>\r\n		<li>Login: Enables registered users to log in securely.</li>\r\n		<li>Forgot Password: Provides a mechanism for users to reset their passwords if forgotten.</li>\r\n		<li>Logout: Allows users to securely log out of their accounts.</li>\r\n		<li>Profile Update: Enables users to update their personal information and preferences.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Property Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Property Viewing: Displays detailed information and media for each property.</li>\r\n		<li>Subscription Details: Allows users to view their current subscription status and details.</li>\r\n		<li>Payment Gateway Integration: Enables secure online payments for subscription plans&nbsp;purchases.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Multi-State Property Listings:</strong></p>\r\n\r\n	<ul>\r\n		<li>Properties are categorized based on the state they belong to, allowing users to easily find listings in their desired location.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Backend Features:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Admin Panel:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admin and Agent Login: Provides separate authentication for administrators and agents.</li>\r\n		<li>Profile Management: Allows admins and agents to update their profiles and preferences.</li>\r\n		<li>Property Management:\r\n		<ul>\r\n			<li>Bulk Property Upload: Supports uploading multiple properties at once using Excel import.</li>\r\n			<li>Manual Property Upload: Enables agents to manually add properties with detailed information.</li>\r\n			<li>Property Editing: Allows admins and agents to modify property details as needed.</li>\r\n			<li>Property Deletion: Provides the ability to remove properties from the platform.</li>\r\n			<li>Property Updates: Allows for real-time updates to property information.</li>\r\n		</ul>\r\n		</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>User and Agent Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admin Control: Enables administrators to manage users and agents, including permissions and access levels.</li>\r\n		<li>Agent Oversight: Provides admins with insights into agent activities and performance.</li>\r\n		<li>Property Details Management: Agents have access to a dashboard where they can view and manage their property listings.</li>\r\n		<li>Property View Count: Tracks the number of times each property listing has been viewed by users, providing valuable insights for agents</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Additional Features:</strong></p>\r\n\r\n<ul>\r\n	<li>Search Functionality: Allows users to search for properties based on various criteria such as location, price, etc.</li>\r\n	<li>Responsive Design: Ensures the platform is accessible and user-friendly across different devices and screen sizes.</li>\r\n	<li>Notifications: Sends email&nbsp; notifications to users for important events such as property updates or subscription renewals.</li>\r\n	<li>Advanced Filters: Enables users to refine property search results based on specific preferences.</li>\r\n	<li>Analytics Dashboard: Provides admins with insights and metrics regarding platform usage, property views, etc.</li>\r\n</ul>', 1, '2024-02-01 21:29:34', '2024-06-30 00:45:28'),
(3, 'Shadi Bookings (Online Services Booking)', 'web development', 'https://shadibookings.com/', 'portfolio/10-05-2024-00-03-421715279622.png', '[\"portfolio\\/2024-05-10-00-03-42017152796220.png\",\"portfolio\\/2024-05-10-00-03-42117152796221.png\",\"portfolio\\/2024-05-10-00-03-42217152796222.png\",\"portfolio\\/2024-05-10-00-03-42317152796223.png\",\"portfolio\\/2024-05-10-00-03-42417152796224.png\",\"portfolio\\/2024-05-10-00-03-42517152796225.png\",\"portfolio\\/2024-05-10-00-03-42617152796226.png\",\"portfolio\\/2024-05-10-00-03-42717152796227.png\",\"portfolio\\/2024-05-10-00-03-42817152796228.png\",\"portfolio\\/2024-05-10-00-03-42917152796229.png\",\"portfolio\\/2024-05-10-00-03-4210171527962210.png\",\"portfolio\\/2024-05-10-00-03-4211171527962211.png\",\"portfolio\\/2024-05-10-00-03-4212171527962212.png\",\"portfolio\\/2024-05-10-00-03-4213171527962213.png\",\"portfolio\\/2024-05-10-00-03-4214171527962214.png\",\"portfolio\\/2024-05-10-00-03-4215171527962215.png\",\"portfolio\\/2024-05-10-00-03-4216171527962216.png\",\"portfolio\\/2024-05-10-00-03-4217171527962217.png\",\"portfolio\\/2024-05-10-00-03-4218171527962218.png\"]', '<p><strong>ShadiBooking Laravel Project&nbsp;</strong></p>\r\n\r\n<p><strong>Introduction:</strong> The ShadiBooking Laravel project is a comprehensive platform designed to cater to all the needs of a wedding ceremony. It offers a wide range of services including catering, pandit services, marriage halls, decoration, transportation, honeymoon destinations, photography, makeup, dresses, banquet and farm venues, entertainment, and DJ services. The project includes both frontend and backend functionalities to ensure a seamless user experience.</p>\r\n\r\n<p><strong>Frontend Features:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>User Profile:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can&nbsp;manage their profiles, including personal information and preferences related to wedding planning.</li>\r\n		<li>Displays a list of vendors that users have contacted or interacted with during their wedding planning process.</li>\r\n		<li>Users can acess many thing after login like services ratings, contact with vendor &amp; etc.</li>\r\n		<li>Users can book services which is needed.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Password Change:</strong></p>\r\n\r\n	<ul>\r\n		<li>Allows users to securely change their passwords for account protection.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Logout:</strong></p>\r\n\r\n	<ul>\r\n		<li>Enables users to securely log out of their accounts.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Service Details:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can view detailed information about each service, including photos, videos, ratings, and reviews to make informed decisions.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Backend Features:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Admin Panel:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admin Login: Secure access for administrators to manage user information and activities.</li>\r\n		<li>User Management: Admins can control user accounts, including registration, profile management, and activity monitoring.</li>\r\n		<li>Vendor Management: Admins can create vendor categories, subcategories, and manage vendor listings.</li>\r\n		<li>City Management: Allows admins to add, edit, or delete cities where wedding services are available.</li>\r\n		<li>Manage subscriber details.</li>\r\n		<li>Manage contact list details.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Vendor Panel:</strong></p>\r\n\r\n	<ul>\r\n		<li>Vendors can register on the platform and choose the appropriate category and subcategory for their services.</li>\r\n		<li>Vendors can create ,edit &amp; update Services.</li>\r\n		<li>Vendors can upload multiple images&nbsp;of Services after every event.</li>\r\n		<li>Vendors can access customer contact details in their panel and via email ntification.</li>\r\n		<li>One-Time Payment: Vendors are required to make a one-time payment for access to the vendor panel, enabling them to upload services and photos, manage bookings, and communicate with customers.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Notification System:</strong></p>\r\n\r\n	<ul>\r\n		<li>Registration Welcome Message: Users receive welcome messages via mobile and email upon registration to introduce them to the platform.</li>\r\n		<li>Service Notifications: Users receive notifications about service updates, bookings, and other relevant information.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Additional Features:</strong></p>\r\n\r\n<ul>\r\n	<li>Secure Payment Gateway: Integration with a secure payment gateway for vendor payments and transactions.</li>\r\n	<li>Service Ratings and Reviews: Allows users to rate and review services they have used, providing valuable feedback for other users.</li>\r\n	<li>Booking Management: Vendors can manage bookings and communicate with customers through the platform.</li>\r\n	<li>Multimedia Gallery: Vendors can upload photos and videos showcasing their services to attract potential customers.</li>\r\n	<li>Responsive Design: Ensures optimal user experience across various devices and screen sizes.</li>\r\n</ul>\r\n\r\n<p>.</p>', 1, '2024-02-18 10:12:43', '2024-06-30 00:46:45'),
(4, 'shikshayan (Scholarship Portal)', 'web development', 'https://shikshayan.awd.world/', 'portfolio/10-05-2024-21-30-581715356858.png', '[\"portfolio\\/2024-05-10-21-57-44017153584640.png\",\"portfolio\\/2024-05-10-21-57-44117153584641.png\",\"portfolio\\/2024-05-10-21-57-44217153584642.png\",\"portfolio\\/2024-05-10-21-57-44317153584643.png\",\"portfolio\\/2024-05-10-21-57-44417153584644.png\",\"portfolio\\/2024-05-10-21-57-44517153584645.png\",\"portfolio\\/2024-05-10-21-57-44617153584646.png\",\"portfolio\\/2024-05-10-21-57-44717153584647.png\",\"portfolio\\/2024-05-10-21-57-44817153584648.png\",\"portfolio\\/2024-05-10-21-57-44917153584649.png\",\"portfolio\\/2024-05-10-21-57-4410171535846410.png\",\"portfolio\\/2024-05-10-21-57-4411171535846411.png\"]', '<p><strong>Introduction:</strong></p>\r\n\r\n<p>Shikshayan Scholarship Exam Portal is a comprehensive platform designed to streamline the process of conducting scholarship exams for students across different classes. With a user-friendly interface, it caters to the needs of students, administrators, and teachers, providing seamless management of scholarship applications, exam creation, question management, and result publication. The portal integrates a secure payment gateway for fee transactions and an SMS system for efficient communication.</p>\r\n\r\n<p><strong>User Panel:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Registration and Login:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can register on the portal and log in securely to access scholarship information and application features.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Scholarship Advertisement:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can view available scholarships advertised on the platform, including eligibility criteria and deadlines.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Application Submission:</strong></p>\r\n\r\n	<ul>\r\n		<li>Applicants can submit their scholarship applications through the portal, providing necessary details and documents.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Payment Processing:</strong></p>\r\n\r\n	<ul>\r\n		<li>After completing the application form, users can proceed to make payments securely through integrated payment gateways.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Admit Card Generation:</strong></p>\r\n\r\n	<ul>\r\n		<li>Once the application is processed, users receive digitally generated admit cards with exam details such as date, time, and venue.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Exam Attempt:</strong></p>\r\n\r\n	<ul>\r\n		<li>On the scheduled date and time, users can attempt the scholarship exam online through the portal.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Application Tracking:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can track the status of their scholarship application, including payment confirmation and exam attendance.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Result Viewing:</strong></p>\r\n\r\n	<ul>\r\n		<li>After the exam, users can view their results on the portal, which are automatically calculated and published.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Profile Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users have access to update their personal information, including contact details and academic records.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Admin Panel:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>User Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins can manage user accounts, including students and teachers, overseeing their information and activities.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Exam Creation:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins have the authority to create scholarship exams, defining parameters such as subjects, duration, and difficulty levels.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Subject Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins can create, edit, update, and delete subjects relevant to the scholarship exams.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Question Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins have control over the creation, editing, updating, and deletion of exam questions and answers.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Data Printing and Export:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins can print and export various details related to exams, questions, and user information for record-keeping purposes.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Teacher Panel:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Question Creation:</strong></p>\r\n\r\n	<ul>\r\n		<li>Teachers can create and submit questions along with their answers for inclusion in scholarship exams.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Scholarship Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Teachers have the option to create scholarship programs, defining criteria and requirements for applicants.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Monitoring and Evaluation:</strong></p>\r\n\r\n	<ul>\r\n		<li>Teachers can monitor exam performance, analyze results, and provide feedback to improve future exams.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Additional Features:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Payment Gateway Integration:</strong></p>\r\n\r\n	<ul>\r\n		<li>The portal integrates a secure payment gateway to facilitate hassle-free fee transactions for scholarship applications.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>SMS System:</strong></p>\r\n\r\n	<ul>\r\n		<li>An SMS system is incorporated to send notifications and reminders to users regarding application deadlines, exam schedules, and result announcements.</li>\r\n	</ul>\r\n	</li>\r\n</ul>\r\n\r\n<p>Shikshayan Scholarship Exam Portal aims to revolutionize the scholarship application process, providing a centralized platform for efficient management and seamless user experience.</p>', 1, '2024-02-18 10:13:47', '2024-05-10 21:57:44'),
(5, 'Srimehi Jewels (Ecommerce)', 'web development', 'https://srimehijewels.com/', 'portfolio/10-05-2024-00-52-331715282553.png', '[\"portfolio\\/2024-05-10-00-52-33017152825530.png\",\"portfolio\\/2024-05-10-00-52-33117152825531.png\",\"portfolio\\/2024-05-10-00-52-33217152825532.png\",\"portfolio\\/2024-05-10-00-52-33317152825533.png\",\"portfolio\\/2024-05-10-00-52-33417152825534.png\",\"portfolio\\/2024-05-10-00-52-33517152825535.png\",\"portfolio\\/2024-05-10-00-52-33617152825536.png\",\"portfolio\\/2024-05-10-00-52-33717152825537.png\",\"portfolio\\/2024-05-10-00-52-33817152825538.png\",\"portfolio\\/2024-05-10-00-52-33917152825539.png\",\"portfolio\\/2024-05-10-00-52-3310171528255310.png\"]', '<p><strong>ShriMehiJewels Laravel E-commerce Project</strong></p>\r\n\r\n<p><strong>Introduction:&nbsp;</strong>The ShriMehiJewels Laravel e-commerce project is an online platform designed for selling jewelry products. It encompasses both frontend and backend functionalities to provide a seamless shopping experience for users. A key feature of this project is automatic currency conversion based on the customer&#39;s country, with prices adjusted according to the metal weight and per gram price. Additionally, the project integrates an online payment gateway for secure and convenient transactions.</p>\r\n\r\n<p><strong>Frontend Features:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>User Login:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can securely log in to their accounts to access personalized features and manage their orders.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Profile Update:</strong></p>\r\n\r\n	<ul>\r\n		<li>Allows users to update their personal information, such as name, email, and contact details.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Change and Forget Password:</strong></p>\r\n\r\n	<ul>\r\n		<li>Provides options for users to change their passwords or recover forgotten passwords securely.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Update Address:</strong></p>\r\n\r\n	<ul>\r\n		<li>Enables users to add, edit, or delete shipping addresses for order delivery.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Manage Order Details:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can view and manage their order history, including order status, tracking information, and invoices.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Product Features:</strong></p>\r\n\r\n	<ul>\r\n		<li>Add to Cart: Users can add products to their shopping cart for future purchase.</li>\r\n		<li>Add to Wishlist: Allows users to save products to a wishlist for future reference or purchase.</li>\r\n		<li>Checkout: Provides a streamlined checkout process for users to complete their purchases online.</li>\r\n		<li>Cash on Delivery: Offers a payment option where users can pay for their orders upon delivery.</li>\r\n		<li>Coupon Codes: Users can apply coupon codes during checkout to avail discounts on their purchases.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Backend Features:</strong></p>\r\n\r\n<ol>\r\n	<li><strong>Admin Panel:</strong>\r\n\r\n	<ul>\r\n		<li>Admin Login: Secure access for administrators to manage the e-commerce platform.</li>\r\n		<li>Currency Management: Admins can create and manage currencies for different countries.</li>\r\n		<li>Metal Type &amp; Quality: Allows admins to define various types and qualities of metals used in jewelry.</li>\r\n		<li>Inquiry Management: Admins can view and respond to inquiries from users regarding products or services.</li>\r\n		<li>Product Management: Admins can create, edit, update, and delete product listings, including images, descriptions, and prices.</li>\r\n		<li>Category Management: Allows admins to create and manage product categories for organizing listings.</li>\r\n		<li>Order Management: Admins can view and manage order details, including status updates, shipping information, and invoices.</li>\r\n		<li>Promo Code Management: Enables admins to create and manage promotional codes for discounts and special offers.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Online Payment Gateway:</strong></p>\r\n\r\n<ul>\r\n	<li>Integration with a secure online payment gateway allows users to make payments using various methods such as credit/debit cards, net banking, or digital wallets.</li>\r\n	<li>Users can securely complete transactions during the checkout process, ensuring a smooth and hassle-free payment experience.</li>\r\n	<li>The payment gateway adheres to industry-standard security protocols to protect sensitive financial information and prevent unauthorized access.</li>\r\n</ul>\r\n\r\n<p><strong>Additional Functionalities:</strong></p>\r\n\r\n<ul>\r\n	<li>Automatic Currency Conversion: Prices are automatically converted to the customer&#39;s local currency based on their country of residence.</li>\r\n	<li>Dynamic Price Calculation: Product prices are calculated based on the metal weight and per gram price, ensuring accurate pricing.</li>\r\n	<li>Responsive Design: The platform is designed to be responsive, providing an optimal viewing experience across various devices and screen sizes.</li>\r\n</ul>', 1, '2024-02-18 10:15:21', '2024-05-10 22:00:38'),
(6, 'Travel Buddy (Travel Agency)', 'Web development', 'https://travel.awd.world/', 'portfolio/10-05-2024-01-15-261715283926.png', '[\"portfolio\\/2024-05-10-01-15-26017152839260.png\",\"portfolio\\/2024-05-10-01-15-26117152839261.png\",\"portfolio\\/2024-05-10-01-15-26217152839262.png\",\"portfolio\\/2024-05-10-01-15-26317152839263.png\",\"portfolio\\/2024-05-10-01-15-26417152839264.png\",\"portfolio\\/2024-05-10-01-15-26517152839265.png\",\"portfolio\\/2024-05-10-01-15-26617152839266.png\",\"portfolio\\/2024-05-10-01-15-26717152839267.png\",\"portfolio\\/2024-05-10-01-15-26817152839268.png\",\"portfolio\\/2024-05-10-01-15-26917152839269.png\",\"portfolio\\/2024-05-10-01-15-2610171528392610.png\"]', '<p><strong>Travel Buddy Laravel Travel Agency Project</strong></p>\r\n\r\n<p><strong>Introduction:</strong> The Travel Buddy Laravel travel agency project is aimed at providing travel packages to various beautiful destinations. It features both frontend for customers and backend for administrators, facilitating seamless communication and management of travel packages and inquiries.</p>\r\n\r\n<p><strong>User Panel:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Travel Package Viewing:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can browse through a variety of travel packages offered by the agency.</li>\r\n		<li>Packages include details such as destination, itinerary, accommodation, activities, and pricing.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Contacting Admin:</strong></p>\r\n\r\n	<ul>\r\n		<li>Users can express interest or inquire about specific travel packages by filling out a contact form.</li>\r\n		<li>Contact form allows users to provide details such as name, contact information, preferred travel dates, and any specific queries they may have.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Admin Panel:</strong></p>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Package Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins have the ability to create new travel packages, including specifying destination details, itinerary, accommodation options, activities, and pricing.</li>\r\n		<li>Existing packages can be edited, updated, or deleted as needed to reflect changes or updates.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Customer Inquiry Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins can view and manage inquiries received from users regarding travel packages.</li>\r\n		<li>Inquiries include details such as user contact information, preferred travel dates, and specific queries.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Contact List Management:</strong></p>\r\n\r\n	<ul>\r\n		<li>Admins can maintain a contact list of users who have expressed interest or made inquiries about travel packages.</li>\r\n		<li>Contact list includes user details such as name, email, and phone number, along with the specific travel packages they are interested in.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Additional Features:</strong></p>\r\n\r\n<ul>\r\n	<li>Responsive Design: The platform is designed to provide an optimal viewing experience across various devices, including desktops, tablets, and mobile phones.</li>\r\n	<li>Authentication and Authorization: Users and admins are required to log in with their respective credentials to access the functionalities specific to their roles.</li>\r\n	<li>Secure Communication: Contact forms and inquiry management ensure that user queries and communication with admins are conducted securely and privately.</li>\r\n</ul>', 1, '2024-05-10 01:15:26', '2024-05-10 21:59:33'),
(7, 'Legal Recovery (Admin Panel)', 'Admin Panel & Api', 'https://legalrecovery.awd.world/', 'portfolio/30-06-2024-00-35-401719687939.png', '[\"portfolio\\/2024-06-30-00-39-40017196881800.png\",\"portfolio\\/2024-06-30-00-39-40117196881801.png\",\"portfolio\\/2024-06-30-00-39-40217196881802.png\",\"portfolio\\/2024-06-30-00-39-40317196881803.png\",\"portfolio\\/2024-06-30-00-39-40417196881804.png\",\"portfolio\\/2024-06-30-00-39-40517196881805.png\",\"portfolio\\/2024-06-30-00-39-40617196881806.png\",\"portfolio\\/2024-06-30-00-39-40717196881807.png\",\"portfolio\\/2024-06-30-00-39-40817196881808.png\",\"portfolio\\/2024-06-30-00-39-40917196881809.png\",\"portfolio\\/2024-06-30-00-39-4010171968818010.png\"]', '<h3><strong>Project Name: Legal Recovery Admin Panel</strong></h3>\r\n\r\n<p><strong>Overview:</strong> Legal Recovery is an advanced admin panel designed exclusively for controlling a mobile app via APIs. It serves three primary user roles: Super Admin, Admin, and Agent, each equipped with specific functionalities tailored to their responsibilities within the legal recovery process.</p>\r\n\r\n<p><strong>User Roles and Capabilities:</strong></p>\r\n\r\n<ol>\r\n	<li><strong>Super Admin:</strong>\r\n\r\n	<ul>\r\n		<li>View comprehensive analytics such as total search history, total admins, and total agents.</li>\r\n		<li>Manage admins (add, edit, update, search, delete).</li>\r\n		<li>Delete search history (individual or all at once).</li>\r\n		<li>Download search history reports in Excel format.</li>\r\n		<li>Has full control over the entire platform&#39;s operations.</li>\r\n	</ul>\r\n	</li>\r\n	<li><strong>Admin:</strong>\r\n	<ul>\r\n		<li>Add vehicle data manually or in bulk via seamless Excel imports, capable of handling millions of records swiftly.</li>\r\n		<li>Share imported data with other admins using specific file names for easy identification.</li>\r\n		<li>Manage shared data received from other admins in a dedicated file share section.</li>\r\n		<li>Delete uploaded Excel data effortlessly in bulk or individually.</li>\r\n		<li>Manage agent operations including add, approve, reject, edit, update, and delete.</li>\r\n		<li>Control and monitor search history within their operational scope.</li>\r\n	</ul>\r\n	</li>\r\n	<li><strong>Agent:</strong>\r\n	<ul>\r\n		<li>Registered under a specific admin, agents access authorized data exclusively.</li>\r\n		<li>Search vehicle data using criteria such as registration number, engine number, etc.</li>\r\n		<li>Download approved vehicle documents as authorized by the admin.</li>\r\n		<li>Maintain personal profiles with capabilities to update data and manage password recovery.</li>\r\n	</ul>\r\n	</li>\r\n</ol>\r\n\r\n<p><strong>Key Features:</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Scalability:</strong> Capable of handling large datasets efficiently, ensuring optimal performance even with extensive data volumes.</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Data Security and Integrity:</strong> Implements robust measures to safeguard data integrity and ensure secure access control across user roles.</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>User Interface Customization:</strong> Offers both dark and light mode options, enhancing user experience and accessibility based on individual preferences.</p>\r\n	</li>\r\n	<li>\r\n	<p><strong>Single-Click Operations:</strong> Simplifies administrative tasks such as data deletion and bulk operations, saving time and enhancing productivity.</p>\r\n	</li>\r\n</ul>\r\n\r\n<p><strong>Project Impact:</strong> The Legal Recovery admin panel stands out for its sophisticated data management capabilities and user-centric design. By enabling seamless control over extensive data sets, it enhances operational efficiency within legal recovery processes. Developed solely by myself, it showcases expertise in full-stack development, API integration, and UI/UX design.</p>\r\n\r\n<p>This project not only meets but exceeds the stringent demands of managing large-scale data operations in the legal recovery domain. It represents a significant achievement in leveraging technology to streamline administrative workflows and optimize data handling, setting a benchmark for similar applications in the industry.</p>', 1, '2024-06-30 00:35:40', '2024-06-30 00:44:25'),
(8, 'Rakiro (Bpemail , Email Notification Sending system)', 'Email Sending System', 'javascript:void()', 'portfolio/30-06-2024-21-34-551719763495.png', '[\"portfolio\\/2024-06-30-21-34-55017197634950.png\",\"portfolio\\/2024-06-30-21-34-55117197634951.png\",\"portfolio\\/2024-06-30-21-34-55217197634952.png\",\"portfolio\\/2024-06-30-21-34-55317197634953.png\",\"portfolio\\/2024-06-30-21-34-55417197634954.png\",\"portfolio\\/2024-06-30-21-34-55517197634955.png\",\"portfolio\\/2024-06-30-21-34-55617197634956.png\",\"portfolio\\/2024-06-30-21-34-55717197634957.png\",\"portfolio\\/2024-06-30-21-34-55817197634958.png\",\"portfolio\\/2024-06-30-21-34-55917197634959.png\",\"portfolio\\/2024-06-30-21-34-5510171976349510.png\"]', '<p><strong>Project Overview: bpemail - Email Notification Sending Software</strong></p>\r\n\r\n<ul>\r\n	<li>\r\n	<p><strong>Database Integration:</strong></p>\r\n\r\n	<ul>\r\n		<li>Utilizes two databases:\r\n		<ol>\r\n			<li>eCommerce Website Database: Contains user information, including registered customers and purchase details.</li>\r\n			<li>bpemail Database: Stores internal data specific to the bpemail software.</li>\r\n		</ol>\r\n		</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Functionality Overview:</strong></p>\r\n\r\n	<ul>\r\n		<li>\r\n		<p><strong>Email List Management:</strong></p>\r\n\r\n		<ul>\r\n			<li>\r\n			<p><strong>Create List:</strong></p>\r\n\r\n			<ul>\r\n				<li>Allows creation of email lists with comprehensive filtering options:\r\n				<ul>\r\n					<li>Customer filters: Customer code, name, category, territory, country, state, city. Supports selection of active and non-active users.</li>\r\n					<li>Invoice filters: Product code, category, date range.</li>\r\n				</ul>\r\n				</li>\r\n				<li>Ensures all email addresses are validated before creating groups.</li>\r\n			</ul>\r\n			</li>\r\n			<li>\r\n			<p><strong>Group List:</strong></p>\r\n\r\n			<ul>\r\n				<li>Displays created groups with detailed validation statuses (valid/invalid emails).</li>\r\n				<li>Provides management options to correct and handle invalid email addresses.</li>\r\n			</ul>\r\n			</li>\r\n			<li>\r\n			<p><strong>Group Details:</strong></p>\r\n\r\n			<ul>\r\n				<li>Shows group specifics including name, contact count, and options for managing invalid emails. Allows deletion and duplication of groups.</li>\r\n			</ul>\r\n			</li>\r\n		</ul>\r\n		</li>\r\n		<li>\r\n		<p><strong>Email Messaging:</strong></p>\r\n\r\n		<ul>\r\n			<li>\r\n			<p><strong>Create :</strong></p>\r\n\r\n			<ul>\r\n				<li>Compose emails with options for sender, recipient (selected groups), CC recipients for information copies, subject, message content.</li>\r\n				<li>Supports shortcut placeholders for customer-specific information and attachments.</li>\r\n				<li>Includes functionality to send test emails for immediate validation and schedule emails for future delivery.</li>\r\n			</ul>\r\n			</li>\r\n			<li>\r\n			<p><strong>Scheduled&nbsp;:</strong></p>\r\n\r\n			<ul>\r\n				<li>Displays details of scheduled emails, including status and scheduled date/time of sending.</li>\r\n			</ul>\r\n			</li>\r\n		</ul>\r\n		</li>\r\n		<li>\r\n		<p><strong>Automation:</strong></p>\r\n\r\n		<ul>\r\n			<li><strong>Create and View:</strong>\r\n\r\n			<ul>\r\n				<li>Automates email sending based on predefined criteria (sender, recipient categories, subject, message, attachments).</li>\r\n				<li>Allows scheduling of automated emails at specified intervals/days.</li>\r\n				<li>Distinct from one-time scheduled emails, automation runs cyclically based on configured settings.</li>\r\n			</ul>\r\n			</li>\r\n		</ul>\r\n		</li>\r\n		<li>\r\n		<p><strong>Sub-Admin Management:</strong></p>\r\n\r\n		<ul>\r\n			<li>Admin controlled &nbsp;sub-administrators with permissions to:\r\n			<ul>\r\n				<li>Create, edit, view, activate, deactivate, and delete sub admin profiles.</li>\r\n				<li>Excludes access to system-wide configurations managed by primary administrators.</li>\r\n			</ul>\r\n			</li>\r\n		</ul>\r\n		</li>\r\n		<li>\r\n		<p><strong>System Configuration:</strong></p>\r\n\r\n		<ul>\r\n			<li><strong>Common Setup:</strong>\r\n\r\n			<ul>\r\n				<li>Centralizes configuration for SMTP (Simple Mail Transfer Protocol) settings ensuring efficient email delivery.</li>\r\n			</ul>\r\n			</li>\r\n			<li><strong>SMTP Setup:</strong>\r\n			<ul>\r\n				<li>Facilitates addition, modification, and deletion of SMTP configurations, enhancing flexibility in email transmission.</li>\r\n			</ul>\r\n			</li>\r\n		</ul>\r\n		</li>\r\n		<li>\r\n		<p><strong>User Interface:</strong></p>\r\n\r\n		<ul>\r\n			<li>Offers multiple themes (light, dark, auto mode) to cater to user preferences.</li>\r\n			<li>Includes efficient shortcut functionalities designed to enhance user productivity.</li>\r\n		</ul>\r\n		</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Operational Structure:</strong></p>\r\n\r\n	<ul>\r\n		<li>Managed by admins who create and oversee sub-administrators, granting controlled access to system functionalities.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Conclusion:</strong></p>\r\n\r\n	<ul>\r\n		<li>bpemail represents a robust email notification software solution, integrating advanced functionalities for effective email list management, messaging, automation, and administrative control. Its intuitive interface, coupled with powerful features such as comprehensive filtering, scheduled emailing, and configurable SMTP setups, positions it as a pivotal tool for modern email communication strategies.</li>\r\n	</ul>\r\n	</li>\r\n</ul>\r\n\r\n<p>This structured presentation emphasizes the software&#39;s capabilities, operational flow, and user-centric design, tailored for efficient business communication needs.</p>', 1, '2024-06-30 21:34:55', '2024-06-30 21:34:55'),
(9, 'MinEmi Check Loan Eligibility', 'React.Js', 'https://minemi.ai/home-loan/check-eligibility/', 'portfolio/04-01-2025-12-53-041735975384.png', '[\"portfolio\\/2025-01-04-12-53-04017359753840.png\",\"portfolio\\/2025-01-04-12-53-04117359753841.png\",\"portfolio\\/2025-01-04-12-53-04217359753842.png\",\"portfolio\\/2025-01-04-12-53-04317359753843.png\",\"portfolio\\/2025-01-04-12-53-04417359753844.png\",\"portfolio\\/2025-01-04-12-53-04517359753845.png\"]', '<p><strong>Introduction:&nbsp;</strong>The <strong>MinEmi Check Loan Eligibility</strong> project involves a platform designed to help users assess their eligibility for various loan products, track the status of their current loans, and calculate their EMI details for new loans. The project has been developed across three websites, each tailored to offer slightly different content but following the same core functionalities.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<h3>Features:</h3>\r\n\r\n<ol>\r\n	<li>\r\n	<p><strong>Loan Status and Details</strong>:</p>\r\n\r\n	<ul>\r\n		<li>Users can easily check the status of their ongoing loans.</li>\r\n		<li>Provides a comprehensive overview of all active loans, including how many are running and their respective details.</li>\r\n		<li>Allows users to see the exact days remaining for each loan.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Eligibility Check</strong>:</p>\r\n\r\n	<ul>\r\n		<li>Users can input personal details through a form to check their eligibility for different types of loans.</li>\r\n		<li>An OTP (One-Time Password) verification is provided to ensure the authenticity of the user&#39;s data before checking eligibility.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Loan Eligibility Results</strong>:</p>\r\n\r\n	<ul>\r\n		<li>The platform provides clear feedback on whether the user is eligible for a specific loan or not.</li>\r\n		<li>Detailed information about loan eligibility criteria is displayed, ensuring the user understands why they qualify or don&#39;t qualify for a loan.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Loan Calculation</strong>:</p>\r\n\r\n	<ul>\r\n		<li>Users can calculate the loan amount they can apply for, as well as their loan tenure.</li>\r\n		<li>EMI (Equated Monthly Installment) calculations are provided based on the entered loan amount and tenure.</li>\r\n		<li>This helps users plan their finances more effectively.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Application Process</strong>:</p>\r\n\r\n	<ul>\r\n		<li>After checking their eligibility, users can apply for a loan directly through an easy-to-use form.</li>\r\n		<li>The platform guides the user through the application process, ensuring a seamless experience.</li>\r\n	</ul>\r\n	</li>\r\n	<li>\r\n	<p><strong>Loan Score and Ranking</strong>:</p>\r\n\r\n	<ul>\r\n		<li>Users receive a credit score and loan ranking based on their eligibility and financial profile.</li>\r\n		<li>This ranking helps users understand their financial standing and improves decision-making when it comes to loan applications.</li>\r\n	</ul>\r\n	</li>\r\n</ol>', 1, '2025-01-04 12:53:04', '2025-01-04 12:53:04');

